public int[] seriesUp(int n)
{
    int length = n * (n + 1) / 2;
    int[] newArray = new int[length];
    int counter = 0;
    for (int i = 0; i < length; i++)
    {
        counter = i;
		for (int j = 1; j <= i + 1; j++)
        {
            newArray[counter] = j;
            counter++;
        }
        i = i + counter;
    }
    return newArray;
}

public int caughtSpeeding(int speed, boolean isBirthday)
{
    if (isBirthday == true)
    {
        speed = speed - 5;
    }
    if (speed <= 60)
    {
        speed = 0; 
    }
    else if (61 <= speed <= 80)
    {
        speed = 1;    
    }
    else if (speed >= 81)
    {
        speed = 2;
    }
}

