public String plusOut(String str, String word)
{
    int len = str.length();
    int wordLen = word.length();
    int j = 0;
 	for (int i = 0; i < len; i++)
    {
        if (str.charAt(i) == word.charAt(j))
        {
            if (j < wordLen - 1)
           		 j = j + 1;
        }
        else
        {
            str.replace(str.charAt(i), '+');
        }
    }
    return str;
}

public int[] seriesUp(int n)
{
    int length = n * (n + 1) / 2;
    int[] newArray = new int[length];
    int counter = 0;
    for (int i = 0; i < length; i++)
    {
		if (i == 0)
        {
            newArray[i] = 1;
        }
        else
        {
            counter = i;
			for (int j = 1; j <= i; j++)
            {
                newArray[counter] = j;
                counter++;
            }
            i = i + counter;
        }
    }
    return newArray;
}

